#include<bits/stdc++.h>
using namespace std;
int f[101],cost[101][101],dis[101],q[10010];
int d[101],day,n,k,m;
vector<pair<int,int>> mp[101];
bool flag[101],vis[101];
int calc(int s,int e)
{
    memset(flag,0,sizeof(flag));
    memset(vis,0,sizeof(vis));
    memset(dis,0x3f,sizeof(dis));
    for(int i=1;i<=n;i++)
    {
        for(int j=s;j<=e;j++)
        {
            if(d[j]&(1<<i))
            {
                flag[i]=1;
            }
        }
    }
    queue<int> q;
    q.push(1);
    vis[1]=1;
    dis[1]=0;
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        vis[t]=0;
        for(auto i:mp[t])
        {
            int v=i.first,val=i.second;
            if(!flag[v]&&dis[v]>dis[t]+val)
            {
                dis[v]=dis[t]+val;
                if(!vis[v])
                {
                    vis[v]=1;
                    q.push(v);
                }
            }
        }
    }
    return dis[n];
}
int main()
{
    scanf("%d%d%d%d",&day,&n,&k,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        mp[u].push_back(make_pair(v,w));
        mp[v].push_back(make_pair(u,w));
    }
    int c;
    scanf("%d",&c);
    for(int i=1;i<=c;i++)
    {
        int x,a,b;
        scanf("%d%d%d",&x,&a,&b);
        for(int j=a;j<=b;j++)
        {
            d[j]|=(1<<x);
        }
    }
    for(int i=1;i<=day;i++)
    {
        for(int j=i;j<=day;j++)
        {
            cost[i][j]=calc(i,j);
        }
    }
    memset(f,0x3f,sizeof(f));
    f[0]=0;
    for(int i=1;i<=day;i++)
    {
        for(int j=0;j<i;j++)
        {
            if(cost[j+1][i]<1e9)
            {
                f[i]=min(f[i],f[j]+(i-j)*cost[j+1][i]+k);
            }
        }
    }
    printf("%d",f[day]-k);
    return 0;
}
